// =================================================================
// Bulgarian stress accent lookup via rechnik.chitanka.info
// Debug version — adds 'debug' field to output for diagnostics
// =================================================================

const rawText = $input.item.json.choices?.[0]?.message?.content || $input.item.json.text || '';
const debugLog = [];

// Detect language and strip marker (handles marker anywhere in string)
const isBulgarian = /LANG:BG/i.test(rawText);
const cleanText = rawText.replace(/\s*LANG:(BG|RU)\s*/gi, '').trim();

debugLog.push({ step: 'input', rawText, isBulgarian, cleanText });

if (!isBulgarian) {
  return [{ json: { text: cleanText, isBulgarian: false, debug: debugLog } }];
}

// ---- Helpers ----

function countVowels(word) {
  return (word.match(/[аеиоуъяюАЕИОУЪЯЮ]/g) || []).length;
}

function stripAccents(str) {
  return str.normalize('NFD').replace(/[\u0300\u0301]/g, '').normalize('NFC');
}

function vowelPositions(word) {
  const positions = [];
  const chars = [...word];
  for (let i = 0; i < chars.length; i++) {
    if (/[аеиоуъяюАЕИОУЪЯЮ]/i.test(stripAccents(chars[i]))) {
      positions.push(i);
    }
  }
  return positions;
}

function stressedVowelIndex(stressedWord) {
  const nfd = [...stressedWord.normalize('NFD')];
  const nfc = [...stressedWord.normalize('NFC')];
  let nfcIdx = 0, nfdIdx = 0;
  const nfcToNfd = [];
  while (nfcIdx < nfc.length) {
    nfcToNfd.push(nfdIdx);
    nfdIdx++;
    while (nfdIdx < nfd.length && nfd[nfdIdx] >= '\u0300' && nfd[nfdIdx] <= '\u036f') nfdIdx++;
    nfcIdx++;
  }
  const vowelIdxs = vowelPositions(stressedWord.normalize('NFC'));
  for (let vi = 0; vi < vowelIdxs.length; vi++) {
    const nfcPos = vowelIdxs[vi];
    const nfStart = nfcToNfd[nfcPos];
    const nfEnd = nfcToNfd[nfcPos + 1] || nfd.length;
    const hasAccent = nfd.slice(nfStart, nfEnd).some(c => c === '\u0300' || c === '\u0301');
    if (hasAccent) return vi;
  }
  return -1;
}

function applyStressAt(word, vi) {
  const chars = [...word];
  const positions = vowelPositions(word);
  if (vi < 0 || vi >= positions.length) return word;
  chars.splice(positions[vi] + 1, 0, '\u0300');
  return chars.join('').normalize('NFC');
}

function decodeHtmlEntities(str) {
  return str
    .replace(/&#(\d+);/g, (_, code) => String.fromCodePoint(parseInt(code, 10)))
    .replace(/&#x([0-9a-fA-F]+);/g, (_, code) => String.fromCodePoint(parseInt(code, 16)));
}

function extractStressedFromHtml(html, plainWordLower) {
  html = decodeHtmlEntities(html);
  // Level 1: name-stressed span
  const spanRe = /id="name-stressed_\d+"[^>]*>([^<]+)<\/span>/g;
  let m;
  while ((m = spanRe.exec(html)) !== null) {
    const candidate = m[1].trim();
    if (stripAccents(candidate).toLowerCase() === plainWordLower) return candidate;
  }
  // Level 2: any accented Cyrillic token matching our word
  const htmlNFD = html.normalize('NFD');
  const cyrRe = /[\u0400-\u04ff][\u0400-\u04ff\u0300\u0301]*/g;
  const freq = {};
  let cm;
  while ((cm = cyrRe.exec(htmlNFD)) !== null) {
    const raw = cm[0].normalize('NFC');
    const plain = stripAccents(raw).toLowerCase();
    if (plain === plainWordLower && raw !== plain) {
      freq[raw] = (freq[raw] || 0) + 1;
    }
  }
  const variants = Object.entries(freq);
  if (variants.length === 0) return null;
  return variants.sort((a, b) => b[1] - a[1])[0][0];
}

function extractBaseFormPath(html) {
  // Allow any whitespace/tags between "на" and the <a href
  // Also decode HTML entities in the path
  const m = html.match(/производна форма[\s\S]*?на[\s\S]*?<a href="(\/w\/[^"]+)"/);
  if (!m) return null;
  return m[1]; // returns first match (first base form)
}

async function fetchHtml(path) {
  const url = `https://rechnik.chitanka.info${path}`;
  // Try all available HTTP methods in n8n Code node
  const methods = [
    // 1. this.helpers.httpRequest (n8n built-in, most common)
    async () => {
      const r = await this.helpers.httpRequest({ method: 'GET', url, returnFullResponse: true });
      return r.body;
    },
    // 2. this.helpers.request (older n8n API)
    async () => {
      return await this.helpers.request({ method: 'GET', uri: url });
    },
    // 3. axios (sometimes available as global)
    async () => {
      const r = await axios.get(url);
      return r.data;
    },
    // 4. got (sometimes available as global)
    async () => {
      const r = await got(url);
      return r.body;
    },
  ];

  for (let i = 0; i < methods.length; i++) {
    try {
      const body = await methods[i]();
      if (body && body.length > 0) {
        debugLog.push({ step: 'http_ok', path, method: i, bodyLen: body.length });
        return body;
      }
    } catch(e) {
      debugLog.push({ step: 'http_try', path, method: i, error: e.message });
    }
  }
  debugLog.push({ step: 'http_error', path, error: 'all methods failed' });
  return null;
}

async function fetchStressedWord(word) {
  const cleanWord = word.toLowerCase().replace(/[^\u0400-\u04ff]/g, '');
  if (!cleanWord) return null;

  const path = `/w/${encodeURIComponent(cleanWord)}`;
  const html = await fetchHtml(path);
  if (!html) {
    debugLog.push({ step: 'no_html', word: cleanWord });
    return null;
  }

  const direct = extractStressedFromHtml(html, cleanWord);
  debugLog.push({ step: 'direct_lookup', word: cleanWord, result: direct });
  if (direct) return direct;

  const basePath = extractBaseFormPath(html);
  debugLog.push({ step: 'base_path', word: cleanWord, basePath });
  if (!basePath) return null;

  const baseHtml = await fetchHtml(basePath);
  if (!baseHtml) return null;

  const baseWord = decodeURIComponent(basePath.replace('/w/', ''));
  const stressedBase = extractStressedFromHtml(baseHtml, baseWord.toLowerCase());
  debugLog.push({ step: 'base_stressed', baseWord, stressedBase });
  if (!stressedBase) return null;

  const vi = stressedVowelIndex(stressedBase);
  debugLog.push({ step: 'vowel_index', stressedBase, vi });
  if (vi < 0) return null;

  const vowelIdxs = vowelPositions(cleanWord);
  const targetVi = vi < vowelIdxs.length ? vi : vowelIdxs.length - 1;
  return applyStressAt(cleanWord, targetVi);
}

// ---- Tokenise ----
function tokenise(text) {
  return text.split(/([\u0400-\u04ff]+(?:['-][\u0400-\u04ff]+)*)/u);
}

// ---- Main ----
const tokens = tokenise(cleanText);
const processedTokens = [];

debugLog.push({ step: 'tokens', tokens });

for (let i = 0; i < tokens.length; i++) {
  const token = tokens[i];
  if (i % 2 === 0) { processedTokens.push(token); continue; }

  if (countVowels(token) <= 1) {
    debugLog.push({ step: 'skip_monosyllable', token });
    processedTokens.push(token);
    continue;
  }

  const stressed = await fetchStressedWord(token);
  debugLog.push({ step: 'result', token, stressed });

  if (stressed) {
    const isCapital = token[0] === token[0].toUpperCase() && token[0] !== token[0].toLowerCase();
    processedTokens.push(isCapital ? stressed[0].toUpperCase() + stressed.slice(1) : stressed);
  } else {
    processedTokens.push(token);
  }
}

return [{ json: { text: processedTokens.join(''), originalText: cleanText, isBulgarian: true, debug: debugLog } }];

